 * The 4-loop coefficient is taken from \arxiv{2205.02249}.
 *
 * \todo Enable CRTP use (through Pert_coeffs) at four loops.
 *       Requires splitting lower orders into quark/gluon cases,
 *       with naive Casimir scaling at those orders an implementation detail.
 */
//------------------------------------------------------------------------------
struct NP_model_gammanu
{
   enum Model_nu
   {
      tanh_1,
      tanh_2,
      tanh_6,
      frac_1,
      frac_2,
      exp_1,
      exp_2,
      hyp_tangent = tanh_2,  /// backward compatibility only
      linear = frac_1        /// backward compatibility only
   };

   double lambda_inf_nu {0.};          /// old c_nu = lambda_inf/2
   double lambda2_nu {0.};             /// old w_nu = sqrt(lambda2/2)
   double lambda4_nu {0.};
   double b0_bmax_nu {0.};
   Model_nu np_model_nu {};

   double bStar(double bT) const
   {
      return b0_bmax_nu != 0. ? pow(pow<6>(b0<>/bT) + pow<6>(b0_bmax_nu), -1./6.) : bT/b0<>;
   }

   double model_gammanu(double bT) const
   {
      if (lambda_inf_nu == 0.)
         return 0.;

      auto bT2 = pow<2>(bT);
      auto arg = (lambda2_nu + lambda4_nu * bT2) * bT2 / lambda_inf_nu;
      double func = 0.;

      switch (np_model_nu) {
         case tanh_1:
            arg += (2./3.)*pow<2>(lambda2_nu * bT2 / lambda_inf_nu);
            func = pow<2>(tanh(sqrt(arg)));
            break;
         default:
         case tanh_2:
            func = tanh(arg);
            break;
         case tanh_6:
            arg += 0.0007 * pow<3>(bT2) / lambda_inf_nu;
            func = tanh(arg);
            break;
         case frac_1:
            arg += pow<2>(lambda2_nu * bT2 / lambda_inf_nu);
            func = arg/(1. + arg);
            break;
         case frac_2:
            func = arg/sqrt(1. + pow<2>(arg));
            break;
         case exp_1:
            arg += 0.5*pow<2>(lambda2_nu * bT2 / lambda_inf_nu);
            func = -expm1(-arg);
            break;
         case exp_2:
            func = sqrt(-expm1(-pow<2>(arg)));
            break;
      }

      return -lambda_inf_nu * func;
   };
};

//------------------------------------------------------------------------------
class Gamma_nu : public Pert_coeffs<Gamma_nu, 2>
{
   public:
      using G = QCD;
      using Group = G;
      using Color = Color_2to0;

      static constexpr Run_order max_run_order = N4LL;

      /// Container for theory nuisance parameters
      struct TNPs
      {
         TNP_adm gamma_cusp;
         TNP_adm gamma_nu;
      };

      Gamma_nu(Color channel, Run_order order, RunningCoupling<G>& alphas, int nf);

      /// \name Queries and Accessors
      ///@{
      Color color() const                      { return _color; }
      Run_order order() const                  { return _order; }
      const RunningCoupling<G>& alphas() const { return _alphas; }
      int nf() const                           { return _nf; }
      RGE_solution rge_type() const            { return _rge_type; }

      void set_color(Color color);
      void set_order(Run_order order);
      void set_nf(int nf);

      void set_np_model(const NP_model_gammanu& model);

      void set_rge_type(RGE_solution rge_type);

      void set_tnps(const TNPs& tnps);
      ///@}

      /// full resummed rapidity anomalous dimension
      double operator()(double bT, double mu0, double mu) const;

      /// \name Anomalous dimension coefficients
      ///@{

      /// Boundary condition at mu = b0/bT for nf flavors in MSbar, using the exponential regulator.
      static constexpr double _0(int) { return 0.; }
      static constexpr double _1(int nf);
      static constexpr double _2(int nf);

      /// \warning This already includes all color factors, unlike lower orders which have C_R scaled out.
      template <typename G::Representation r>
      static constexpr double _3(int nf);

      /// Boundary condition at canonical scale including TNPs.
      static double _0(int nf, const TNP_adm& tnp);
      static double _1(int nf, const TNP_adm& tnp);
      static double _2(int nf, const TNP_adm& tnp);

      /// \warning This already includes all color factors, unlike lower orders which have C_R scaled out.
      double _3(int nf, const TNP_adm& tnp) const;

      /// Fixed-order coefficients at \f$ L_b = \ln(\mu^2 b_T^2/b_0^2) \f$.
      double _0(double Lb) const;
      double _1(double Lb) const;
      double _2(double Lb) const;
